module down_counter(
   input                clk ,
   input                rst,
   input                load,
   input                en,
   input  [31:0]        load_val,

   output reg [31:0]    count  
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt)begin
        if(rst) 
            count <= 32'd0;
        else if(load) 
            count <= load_val;
        else if(en) 
            count <= count - 1;
    end
endmodule
